request.query:
prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT
  ?organization
  ?orgId
  (COUNT(DISTINCT ?model) AS ?modelCount)
  (COUNT(DISTINCT ?definitions) AS ?definitionsCount)
WHERE {
  ?organization a bboExt:Organization ;
                tai:organizationId ?orgId ;
                tai:belongsTo ?corpus .
  FILTER(?orgId = "67e70970f0404a7e87122700ad26d87b")

  OPTIONAL { ?model a bboExt:Model ; tai:belongsTo ?organization . }
  OPTIONAL { ?definitions tai:belongsTo ?model . }
}
GROUP BY ?organization ?orgId
LIMIT 25
